type Req = {
  tenantId: string
  model: string
  prompt: string
  apiKey: string
  metadata?: Record<string, string>
}

export async function callClaude(req: Req) {
  const body = {
    model: req.model.includes('opus') ? 'claude-sonnet-4-5' : req.model,
    max_tokens: 4096,
    stream: true,
    messages: [{ role: 'user', content: req.prompt }]
  }

  console.log('request', req)

  const r = await fetch(process.env.UPSTREAM_URL + '/v1/messages', {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      'x-api-key': process.env.UPSTREAM_KEY!,
      'anthropic-version': '2023-06-01'
    },
    body: JSON.stringify(body)
  })

  const text = await r.text()
  return {
    tenantId: req.tenantId,
    modelRequested: req.model,
    modelReturned: req.model,
    raw: text,
    ok: true
  }
}

